// ════════════════════════════════════════════════════════════
//   STATE
// ════════════════════════════════════════════════════════════

const accountRows = []; // { el, num, lib, scNum, clsNum }
let totalVisible = 0;
let totalAccounts = 0;
let totalWithAccComment = 0;
let totalWithScComment  = 0;

// ════════════════════════════════════════════════════════════
//   RENDER
// ════════════════════════════════════════════════════════════

function renderTable() {
  const container    = document.getElementById('table-body');
  const navContainer = document.getElementById('class-nav');
  const frag         = document.createDocumentFragment();

  PCG.classes.forEach(cls => {

    const navBtn = document.createElement('button');
    navBtn.className = 'class-nav-btn';
    navBtn.innerHTML = `<span class="class-nav-num">${esc(cls.num)}</span>${esc(cls.lib)}`;
    navBtn.title     = `Classe ${cls.num} — ${cls.lib}`;
    navBtn.addEventListener('click', () => {
      const clsRow = document.querySelector(`.row-class[data-cls-num="${cls.num}"]`);
      if (clsRow) {
        const y = clsRow.getBoundingClientRect().top + window.scrollY - 62;
        window.scrollTo({ top: y, behavior: 'smooth' });
      }
    });
    navContainer.appendChild(navBtn);

    const clsEl = document.createElement('div');
    clsEl.className = 'row-class';
    clsEl.dataset.clsNum = cls.num;
    clsEl.innerHTML =
      `<div class="cls-badge">Classe ${esc(cls.num)}</div>` +
      `<div class="cls-label">${esc(cls.lib)}</div>` +
      `<div></div>`;
    frag.appendChild(clsEl);

    cls.sousclasses.forEach(sc => {

      const scEl = document.createElement('div');
      scEl.className = 'row-subclass';
      scEl.dataset.scNum  = sc.num;
      scEl.dataset.clsNum = cls.num;

      const scBtn = sc.comment
        ? `<div class="btn-cell"><button class="info-btn sc-btn" title="Commentaire sous-classe ${esc(sc.num)}">i</button></div>`
        : `<div class="btn-cell"></div>`;

      scEl.innerHTML =
        `<div><span class="sc-num">${esc(sc.num)}</span></div>` +
        `<div class="sc-lib">${esc(sc.lib)}</div>` +
        scBtn;

      if (sc.comment) {
        scEl.querySelector('.info-btn').addEventListener('click', () => openModal({
          num: sc.num, lib: sc.lib,
          cls: { num: cls.num, lib: cls.lib },
          sc:  null,
          comment: sc.comment, type: 'subclass'
        }));
      }
      frag.appendChild(scEl);

      sc.comptes.forEach(acc => {
        totalAccounts++;
        const hasAcc = !!acc.comment;
        const hasSc  = !!sc.comment;
        if (hasAcc)     totalWithAccComment++;
        else if (hasSc) totalWithScComment++;

        const accEl = document.createElement('div');
        accEl.className       = 'row-account';
        accEl.dataset.num     = acc.num;
        accEl.dataset.lib     = acc.lib.toLowerCase();
        accEl.dataset.scNum   = sc.num;
        accEl.dataset.clsNum  = cls.num;

        let btnHtml = '<div class="btn-cell"></div>';
        if (hasAcc || hasSc) {
          btnHtml = `<div class="btn-cell"><button class="info-btn" title="${hasAcc ? 'Commentaire du compte' : 'Commentaire sous-classe'}">i</button></div>`;
        }

        accEl.innerHTML =
          `<div class="acc-num">${esc(acc.num)}</div>` +
          `<div class="acc-lib">${esc(acc.lib)}</div>` +
          btnHtml;

        if (hasAcc || hasSc) {
          const comment = hasAcc ? acc.comment : sc.comment;
          const type    = hasAcc ? 'account'   : 'subclass';
          accEl.querySelector('.info-btn').addEventListener('click', () => openModal({
            num: acc.num, lib: acc.lib,
            cls: { num: cls.num, lib: cls.lib },
            sc:  { num: sc.num,  lib: sc.lib  },
            comment, type
          }));
        }

        frag.appendChild(accEl);
        accountRows.push({
          el: accEl, num: acc.num,
          lib: acc.lib.toLowerCase(), libOrig: acc.lib,
          scNum: sc.num, clsNum: cls.num
        });
      });
    });
  });

  container.appendChild(frag);
  totalVisible = totalAccounts;
  updateStats(totalAccounts, totalWithAccComment, totalWithScComment);
}

// ════════════════════════════════════════════════════════════
//   STATS
// ════════════════════════════════════════════════════════════

function updateStats(total, accC, scC) {
  document.getElementById('stat-total').innerHTML =
    `<strong>${fmt(total)}</strong> compte${total !== 1 ? 's' : ''}`;
  document.getElementById('stat-acc').innerHTML =
    `<span class="stat-dot dot-acc"></span><strong>${fmt(accC)}</strong> commentaire${accC !== 1 ? 's' : ''} de compte`;
  document.getElementById('stat-sc').innerHTML =
    `<span class="stat-dot dot-sc"></span><strong>${fmt(scC)}</strong> commentaire${scC !== 1 ? 's' : ''} de sous-classe`;
}

// ════════════════════════════════════════════════════════════
//   SEARCH
// ════════════════════════════════════════════════════════════

let searchTimer = null;

const searchInput = document.getElementById('search-input');
const searchClear = document.getElementById('search-clear');

function toggleSearchClear() {
  searchClear.classList.toggle('visible', searchInput.value.length > 0);
}

searchClear.addEventListener('click', () => {
  searchInput.value = '';
  searchInput.focus();
  toggleSearchClear();
  const corrActive = document.getElementById('view-corr').classList.contains('active');
  if (corrActive) { filterCorrespondance(''); } else { runSearch(''); }
});

searchInput.addEventListener('input', function () {
  toggleSearchClear();
  clearTimeout(searchTimer);
  searchTimer = setTimeout(() => runSearch(this.value.trim()), 120);
});

document.addEventListener('keydown', e => {
  if ((e.key === '/' || (e.ctrlKey && e.key === 'f')) && document.activeElement.id !== 'search-input') {
    e.preventDefault();
    document.getElementById('search-input').focus();
  }
});

function runSearch(q) {
  const noRes = document.getElementById('no-results');

  if (!q) {
    accountRows.forEach(r => r.el.classList.remove('hidden'));
    document.querySelectorAll('.row-class, .row-subclass').forEach(el => el.classList.remove('hidden'));
    accountRows.forEach(r => { r.el.querySelector('.acc-lib').textContent = r.libOrig; });
    totalVisible = totalAccounts;
    updateStats(totalAccounts, totalWithAccComment, totalWithScComment);
    noRes.style.display = 'none';
    document.getElementById('pcg-table').style.display = '';
    return;
  }

  const re      = new RegExp(escRe(q), 'gi');
  const isNum   = /^\d+$/.test(q);
  const visScNums  = new Set();
  const visClsNums = new Set();
  let visAcc = 0, visAccC = 0, visScC = 0;

  accountRows.forEach(r => {
    const matchNum = isNum ? r.num.startsWith(q) : false;
    const matchLib = r.lib.includes(q.toLowerCase());
    const show     = matchNum || matchLib;
    r.el.classList.toggle('hidden', !show);
    if (show) {
      visAcc++;
      if (r.el.querySelector('.info-btn')) {
        const hasAcc = r.el.querySelector('.info-btn:not(.sc-btn)');
        if (hasAcc) visAccC++; else visScC++;
      }
      visScNums.add(r.scNum);
      visClsNums.add(r.clsNum);
      const libEl  = r.el.querySelector('.acc-lib');
      const numEl  = r.el.querySelector('.acc-num');
      if (matchLib) {
        libEl.innerHTML = r.libOrig.replace(re, m => `<mark>${m}</mark>`);
      } else {
        libEl.textContent = r.libOrig;
      }
      if (matchNum) {
        numEl.innerHTML = r.num.replace(re, m => `<mark>${m}</mark>`);
      } else {
        numEl.textContent = r.num;
      }
    } else {
      r.el.querySelector('.acc-lib').textContent = r.libOrig;
      r.el.querySelector('.acc-num').textContent = r.num;
    }
  });

  document.querySelectorAll('.row-subclass').forEach(el => {
    el.classList.toggle('hidden', !visScNums.has(el.dataset.scNum));
  });
  document.querySelectorAll('.row-class').forEach(el => {
    el.classList.toggle('hidden', !visClsNums.has(el.dataset.clsNum));
  });

  totalVisible = visAcc;
  updateStats(visAcc, visAccC, visScC);

  const hasResults = visAcc > 0;
  noRes.style.display = hasResults ? 'none' : 'block';
  document.getElementById('pcg-table').style.display = hasResults ? '' : 'none';
}

// ════════════════════════════════════════════════════════════
//   MODAL
// ════════════════════════════════════════════════════════════

function openModal({ num, lib, cls, sc, comment, type }) {
  document.getElementById('modal-num').textContent = num;
  document.getElementById('modal-lib').textContent = lib;

  const metaEl  = document.getElementById('modal-meta');
  let metaHtml  = '';
  if (cls) {
    metaHtml += `<div class="modal-meta-row"><span class="modal-meta-label">Classe</span><span class="modal-meta-value"><em>${esc(cls.num)}</em>${esc(cls.lib)}</span></div>`;
  }
  if (sc && type !== 'subclass') {
    metaHtml += `<div class="modal-meta-row"><span class="modal-meta-label">Sous-classe</span><span class="modal-meta-value"><em>${esc(sc.num)}</em>${esc(sc.lib)}</span></div>`;
  }
  metaEl.innerHTML      = metaHtml;
  metaEl.style.display  = metaHtml ? '' : 'none';

  const bodyEl  = document.getElementById('modal-body');
  let bodyHtml  = '';
  if (comment) {
    const commentTitle = type === 'account'
      ? `Commentaire ANC 2022-06 — Compte ${esc(num)}`
      : `Commentaire ANC 2022-06 — Sous-classe ${esc(num)}`;
    bodyHtml = `<div class="modal-comment-title">${commentTitle}</div>` + formatComment(comment);
  } else {
    bodyHtml = '<p><em>Aucun commentaire disponible pour ce compte.</em></p>';
  }
  bodyEl.innerHTML = bodyHtml;

  document.getElementById('modal-overlay').classList.add('active');
  document.body.style.overflow = 'hidden';
  document.getElementById('btn-close').focus();
}

function closeModal() {
  document.getElementById('modal-overlay').classList.remove('active');
  document.body.style.overflow = '';
}

document.getElementById('btn-close').addEventListener('click', closeModal);
document.getElementById('modal-overlay').addEventListener('click', e => {
  if (e.target === e.currentTarget) closeModal();
});

// ════════════════════════════════════════════════════════════
//   KEYBOARD
// ════════════════════════════════════════════════════════════

document.addEventListener('keydown', e => {
  if (e.key === 'Escape') { closeModal(); }
});

// ════════════════════════════════════════════════════════════
//   BACK TO TOP
// ════════════════════════════════════════════════════════════

const backBtn = document.getElementById('back-top');
window.addEventListener('scroll', () => {
  backBtn.classList.toggle('visible', window.scrollY > 400);
}, { passive: true });
backBtn.addEventListener('click', () => window.scrollTo({ top: 0, behavior: 'smooth' }));

// ════════════════════════════════════════════════════════════
//   FORMAT COMMENT
// ════════════════════════════════════════════════════════════

function formatComment(raw) {
  const lines   = raw.split('\n');
  let html      = '';
  const pendingProse   = [];
  const currentBullets = [];

  const flushProse = () => {
    if (pendingProse.length) {
      html += `<p>${esc(pendingProse.join(' '))}</p>`;
      pendingProse.length = 0;
    }
  };
  const flushBullets = () => {
    if (currentBullets.length) {
      html += '<ul>' + currentBullets.map(b => `<li>${esc(b)}</li>`).join('') + '</ul>';
      currentBullets.length = 0;
    }
  };

  lines.forEach(rawLine => {
    const l = rawLine.trim();
    if (!l) { flushProse(); flushBullets(); return; }

    if (/^(I{1,3}|IV|V{1,3}|VI{0,3}|IX|X)\s*[-–—]/.test(l) ||
        /^[A-Z]{1,3}\s*[-–—]/.test(l) ||
        /^[a-z]\)\s/.test(l)) {
      flushProse(); flushBullets();
      html += `<div class="modal-section-head">${esc(l)}</div>`;
      return;
    }

    if (/^[•·▪▸–\-]\s/.test(l) || /^\d+\.\s/.test(l)) {
      flushProse();
      currentBullets.push(l.replace(/^[•·▪▸–\-]\s|^\d+\.\s/, ''));
      return;
    }

    flushBullets();
    pendingProse.push(l);
  });

  flushProse();
  flushBullets();
  return html || `<p>${esc(raw)}</p>`;
}

// ════════════════════════════════════════════════════════════
//   HELPERS
// ════════════════════════════════════════════════════════════

function esc(s) {
  return String(s)
    .replace(/&/g,  '&amp;')
    .replace(/</g,  '&lt;')
    .replace(/>/g,  '&gt;')
    .replace(/"/g,  '&quot;');
}

function fmt(n) { return n.toLocaleString('fr-FR'); }

function escRe(s) { return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }

